import anthropic

client = anthropic.Anthropic()


def stream_response(prompt: str, system: str = "") -> str:
    """Stream tokens as they arrive; collect and return the full text."""
    kwargs = {
        "model":      "claude-opus-4-8",
        "max_tokens": 1024,
        "messages":   [{"role": "user", "content": prompt}],
    }
    if system:
        kwargs["system"] = system

    full_text = []
    with client.messages.stream(**kwargs) as stream:
        for text_chunk in stream.text_stream:
            print(text_chunk, end="", flush=True)   # display as it arrives
            full_text.append(text_chunk)
    print()  # newline after stream
    return "".join(full_text)


result = stream_response("Walk me through gradient descent step by step.")

import time
import anthropic
from anthropic import RateLimitError, APIStatusError, APIConnectionError

client = anthropic.Anthropic()


def call_with_retry(
    prompt: str,
    max_retries: int = 4,
    base_delay: float = 1.0,
) -> str:
    """
    Retry on transient failures with exponential backoff.
    Raises immediately on non-retryable errors (4xx except 429).
    """
    for attempt in range(max_retries + 1):
        try:
            response = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=512,
                messages=[{"role": "user", "content": prompt}],
            )
            return response.content[0].text

        except RateLimitError:
            if attempt == max_retries:
                raise
            delay = base_delay * (2 ** attempt)
            print(f"Rate limited. Retrying in {delay:.1f}s…")
            time.sleep(delay)

        except APIConnectionError:
            if attempt == max_retries:
                raise
            time.sleep(base_delay * (2 ** attempt))

        except APIStatusError as e:
            if e.status_code >= 500:
                if attempt == max_retries:
                    raise
                time.sleep(base_delay * (2 ** attempt))
            else:
                raise   # 4xx (bad request, auth) — don't retry
    raise RuntimeError("Unreachable")

import anthropic, json

client = anthropic.Anthropic()

# Define a tool the model can call
tools = [
    {
        'name': 'get_weather',
        'description': 'Get current temperature for a city.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'city': {'type': 'string', 'description': 'City name'},
                'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit']},
            },
            'required': ['city'],
        },
    }
]

# Simulated tool implementation
def get_weather(city, unit='celsius'):
    temps = {'London': 15, 'Tokyo': 22, 'New York': 18}
    t = temps.get(city, 20)
    if unit == 'fahrenheit':
        t = t * 9/5 + 32
    return {'city': city, 'temperature': t, 'unit': unit}

messages = [{'role': 'user', 'content': 'What is the temperature in Tokyo?'}]

# First turn: model may choose to call a tool
response = client.messages.create(
    model='claude-opus-4-8',
    max_tokens=1024,
    tools=tools,
    messages=messages,
)

if response.stop_reason == 'tool_use':
    # Extract tool call from response
    tool_block = next(b for b in response.content if b.type == 'tool_use')
    tool_result = get_weather(**tool_block.input)

    # Feed result back to the model
    messages += [
        {'role': 'assistant', 'content': response.content},
        {'role': 'user', 'content': [{
            'type': 'tool_result',
            'tool_use_id': tool_block.id,
            'content': json.dumps(tool_result),
        }]},
    ]

    # Second turn: model synthesizes final answer
    final = client.messages.create(
        model='claude-opus-4-8',
        max_tokens=512,
        tools=tools,
        messages=messages,
    )
    print(final.content[0].text)
    # => 'The current temperature in Tokyo is 22 degrees Celsius.'
